#[test]
fn lnnumtype_continuous_with_countby_opens_clean() {
    let body = r#"<w:p><w:r><w:t>Continuous line numbering</w:t></w:r></w:p><w:sectPr><w:lnNumType w:countBy="1" w:restart="continuous"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "lnnumtype_continuous_with_countby_opens_clean — ECMA-376 §17.6.8, §17.18.47, MS-OI29500 §2.1.215: countBy=1 is within Word's 1..100 domain and continuous is a valid ST_LineNumberRestart value, so the section is schema-valid and Word opens it without repair.",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("w:countBy=\"1\""),
        "lnnumtype_continuous_with_countby_opens_clean — §17.6.8: countBy present means line numbering is ON (missing countBy = no numbering); stemma must preserve the authored countBy on reserialize. Got:\n{xml}",
    );
    assert!(
        xml.contains("w:restart=\"continuous\""),
        "lnnumtype_continuous_with_countby_opens_clean — §17.18.47: continuous is an enumerated ST_LineNumberRestart value; stemma preserves the authored restart attribute verbatim. Got:\n{xml}",
    );
}

