#[test]
fn pgborders_offsetfrom_page_canonical_children_opens_clean() {
    let body = r#"<w:p><w:r><w:t>Page borders</w:t></w:r></w:p><w:sectPr><w:pgBorders w:offsetFrom="page"><w:top w:val="dashed" w:sz="4" w:space="24" w:color="auto"/><w:left w:val="dashed" w:sz="4" w:space="24" w:color="auto"/><w:bottom w:val="dashed" w:sz="4" w:space="24" w:color="auto"/><w:right w:val="dashed" w:sz="4" w:space="24" w:color="auto"/></w:pgBorders></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "pgborders_offsetfrom_page_canonical_children_opens_clean — ECMA-376 §17.6.10, §17.18.63: offsetFrom=page is an enumerated ST_PageBorderOffset value and the four edge children are valid CT_Border definitions in the spec's canonical order, so the section is schema-valid and Word opens it without repair.",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("w:offsetFrom=\"page\""),
        "pgborders_offsetfrom_page_canonical_children_opens_clean — MS-OI29500 §2.1.217: Word's offsetFrom default is text, so the explicit non-default offsetFrom=page must be preserved verbatim by stemma's passthrough reserialize. Got:\n{xml}",
    );

    // xmlRegex `<w:top[^>]*/>\s*<w:left[^>]*/>\s*<w:bottom[^>]*/>\s*<w:right[^>]*/>`
    // translated to an ordering check (no `regex` crate in dev-deps): the
    // §17.6.10 CT_PageBorders child sequence is top, left, bottom, right; an
    // untouched pgBorders authored in this order must reserialize in the same
    // order. We locate each child tag and assert strictly increasing position.
    let top = xml.find("<w:top");
    let left = xml.find("<w:left");
    let bottom = xml.find("<w:bottom");
    let right = xml.find("<w:right");
    assert!(
        top.is_some() && left.is_some() && bottom.is_some() && right.is_some(),
        "pgborders_offsetfrom_page_canonical_children_opens_clean — §17.6.10: all four CT_PageBorders edge children must survive reserialize (top/left/bottom/right). Got:\n{xml}",
    );
    let (t, l, bo, r) = (top.unwrap(), left.unwrap(), bottom.unwrap(), right.unwrap());
    assert!(
        t < l && l < bo && bo < r,
        "pgborders_offsetfrom_page_canonical_children_opens_clean — §17.6.10 CT_PageBorders child sequence is top, left, bottom, right; stemma must preserve that order on passthrough. Got positions top={t} left={l} bottom={bo} right={r}:\n{xml}",
    );
}

